import{_ as a,o as t,c as r,ag as o}from"./chunks/framework.B9unkguw.js";const m=JSON.parse('{"title":"Parameters","description":"","frontmatter":{},"headers":[],"relativePath":"en/qgc-user-guide/setup_view/parameters.md","filePath":"en/qgc-user-guide/setup_view/parameters.md"}'),s={name:"en/qgc-user-guide/setup_view/parameters.md"};function n(i,e,l,h,p,c){return t(),r("div",null,e[0]||(e[0]=[o('<h1 id="parameters" tabindex="-1">Parameters <a class="header-anchor" href="#parameters" aria-label="Permalink to &quot;Parameters&quot;">​</a></h1><p>The <em>Parameters</em> screen allows you to find and modify any of the parameters associated with the vehicle.</p><div class="tip custom-block"><p class="custom-block-title">Having trouble?</p><p>If parameters fail to download, see <a href="./../troubleshooting/parameter_download.html">Parameter Download Failures</a>.</p></div><div class="info custom-block"><p class="custom-block-title">INFO</p><p>PX4 Pro and ArduPilot use different parameter sets, but they are both managed as described in this section.</p></div><h2 id="finding-a-parameter" tabindex="-1">Finding a Parameter <a class="header-anchor" href="#finding-a-parameter" aria-label="Permalink to &quot;Finding a Parameter&quot;">​</a></h2><p>The parameters are organized in groups. Select a group of parameters to view by clicking on the buttons to the left.</p><p>You can also <em>search</em> for a parameter by entering a term in the <em>Search</em> field. This will show you a list of all parameter names and descriptions that contain the entered substring (press <strong>Clear</strong> to reset the search).</p><h2 id="changing-a-parameter" tabindex="-1">Changing a Parameter <a class="header-anchor" href="#changing-a-parameter" aria-label="Permalink to &quot;Changing a Parameter&quot;">​</a></h2><p>To change the value of a parameter click on the parameter row in a group or search list. This will open a side dialog in which you can update the value (this dialog also provides additional detailed information about the parameter - including whether a reboot is required for the change to take effect).</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>When you click <strong>Save</strong> the parameter is automatically and silently uploaded to the connected vehicle. Depending on the parameter, you may then need to reboot the flight controller for the change to take effect.</p></div><h2 id="tools" tabindex="-1">Tools <a class="header-anchor" href="#tools" aria-label="Permalink to &quot;Tools&quot;">​</a></h2><p>You can select additional options from the <strong>Tools</strong> menu on the top right hand side of the screen.</p><p><strong>Refresh</strong><br>Refresh the parameter values by re-requesting all of them from the vehicle.</p><p><strong>Reset all to defaults</strong><br>Reset all parameters to their original default values.</p><p><strong>Load from file / Save to file</strong><br>Load parameters from an existing file or save your current parameter settings to a file.</p><p><strong>Clear RC to Param</strong><br>This clears all associations between RC transmitter controls and parameters. For more information see: <a href="./../setup_view/radio.html#param-tuning-channels-px4">Radio Setup &gt; Param Tuning Channels</a>.</p><p><strong>Reboot Vehicle</strong><br>Reboot the vehicle (required after changing some parameters).</p>',17)]))}const u=a(s,[["render",n]]);export{m as __pageData,u as default};
